// Append to packages/data/prisma/schema.prisma (anywhere among the other
// standalone/no-relation models, e.g. next to ChatActivityEvent). No relation
// fields to Tenant/Chat are declared, matching the ChatActivityEvent pattern,
// so this model is a self-contained addition that does not require touching
// any other model block.
model KnownAdmin {
  id        String   @id @default(cuid())
  tenantId  String
  chatId    String
  adminId   BigInt
  createdAt DateTime @default(now())

  @@unique([tenantId, chatId, adminId])
  @@index([tenantId, chatId])
  @@map("known_admins")
}

