  private async handleExternalAdminAuditCommand(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    if (update.command?.name !== "auditoria_admins_externos") {
      return null;
    }

    const chatId = update.chat.chatId;
    if (!chatId || !context.chatId) {
      return { text: "Este comando se usa dentro de un grupo." };
    }

    if (!(await this.isGroupAdmin(chatId, update.user.userId))) {
      return {
        text: "Solo los administradores del grupo pueden auditar admins externos.",
      };
    }

    let admins: readonly {
      userId: bigint;
      username: string | undefined;
      firstName: string | undefined;
      isOwner: boolean;
      customTitle: string | undefined;
    }[];
    try {
      const outcome = await this.telegramGateway.getChatAdministrators({
        chatId,
        token: this.telegramToken(),
      });
      admins = outcome.admins ?? [];
    } catch {
      return {
        text: "Telegram rechazó la operación. Comprueba que soy admin con permisos suficientes.",
      };
    }

    const knownAdmins = await this.knownAdminRepository.listKnownAdmins(
      context.tenantId,
      context.chatId,
    );
    // Telegram user ids fit comfortably inside Number.MAX_SAFE_INTEGER, so the
    // bigint -> number conversion here is safe (unlike chat ids, which can
    // exceed it and stay bigint throughout the codebase).
    const known = knownAdmins.map((id) => Number(id));
    const current = admins.map((admin) => Number(admin.userId));
    const result = detectExternalPromotions(known, current);

    await this.repository.recordAudit({
      tenantId: context.tenantId,
      actorType: "user",
      action: "security.external_admin_audit",
      resourceType: "chat",
      resourceId: chatId.toString(),
      ...(context.userId ? { actorId: context.userId } : {}),
      payload: { flagged: result.newAdmins, alert: result.alert },
    });

    if (!result.alert) {
      return {
        text: "🛡️ Auditoría de admins externos: todos los administradores actuales fueron promovidos desde Modryva. Sin alertas.",
      };
    }

    const byId = new Map(admins.map((admin) => [Number(admin.userId), admin]));
    const lines = result.newAdmins.map((id) => {
      const info = byId.get(id);
      const label = info?.username
        ? `@${info.username}`
        : (info?.firstName ?? `id ${id}`);
      const title = info?.customTitle ? ` (${info.customTitle})` : "";
      const owner = info?.isOwner ? " · owner" : "";
      return `• ${label}${title} — id ${id}${owner}`;
    });

    return {
      text: [
        `🚨 Auditoría de admins externos: ${result.newAdmins.length} admin(es) detectados fuera de Modryva.`,
        ...lines,
        "",
        "Esto es solo una alerta informativa: nadie fue degradado automáticamente. Si corresponde, revisa y actúa manualmente con /demote.",
      ].join("\n"),
    };
  }

